fn encodeAllBlocks(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardDecodeArgsT(Config.WeightBuffer),
) void {
    std.debug.assert(
        args.q_proj.len == Config.num_layers,
    );
    std.debug.assert(args.position + 1 > 0);

    const seq_len: u32 = args.position + 1;
    for (0..Config.num_layers) |i| {
        const idx: u32 = @intCast(i);
        const block_args = blockArgsFromDecodeT(
            Config.WeightBuffer,
            args,
            idx,
            seq_len,
        );
        forwardBlock(
            Config,
            device,
            encoder,
            pipelines,
            block_args,
        );
    }
}

/// Encode final RMSNorm on the residual, then dispatch
/// the LM head QMV to produce [vocab_size] f32 logits.
fn encodeFinalNormAndLMHead(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardDecodeArgsT(Config.WeightBuffer),
) void {
    std.debug.assert(args.lm_head.packed_count > 0);
    std.debug.assert(args.final_norm_scale.value != null);

    dispatchRMSNorm(
        device,
        encoder,
        if (comptime Config.quant_format == .q4_mlx)
            pipelines.rms_norm_bf16_f16out
        else
            pipelines.rms_norm_f16out,
        args.residual,
        args.final_norm_scale,
        args.norm_out,
        .{
            .hidden_size = Config.hidden_size,
            .num_tokens = 1,
            .eps = 1e-6,
        },
    );
    bufferBarrier(encoder);
    const lm_dims = QMVDims{
        .M = Config.vocab_size,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16in(
            device,
            encoder,
            args.lm_head,
            args.norm_out,
            args.logits,
            lm_dims,
        );
    } else {
        dispatchQMVf16in(
            device,
            encoder,
            args.lm_head,
            args.norm_out,
            args.logits,
            lm_dims,
        );
    }
}

/// Construct block args for one layer by indexing into the
/// per-layer slices of the decode args.  Activation scratch
/// buffers are shared across all layers.
fn blockArgsFromDecodeT(
    comptime WeightBuf: type,
    args: ForwardDecodeArgsT(WeightBuf),
    layer_index: u32,
    seq_len: u32,
) ForwardBlockArgsT(WeightBuf) {
    std.debug.assert(layer_index < args.q_proj.len);
    std.debug.assert(seq_len > 0);

    const i = layer_index;
    return .{
        .q_proj = args.q_proj[i],
        .k_proj = args.k_proj[i],
        .v_proj = args.v_proj[i],
        .o_proj = args.o_proj[i],
        .gate_proj = args.gate_proj[i],

pub fn forwardBlock(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    args: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    comptime {
        std.debug.assert(Config.hidden_size > 0);
        std.debug.assert(Config.num_layers > 0);
    }
    std.debug.assert(args.seq_len > 0);
    std.debug.assert(
        args.position < Config.max_context_length,
    );
    std.debug.assert(
        args.seq_len <= Config.max_context_length,
    );

    encodeAttentionHalf(
        Config,
        device,
        encoder,
        pipelines,
        args,
    );
    encodeMLPHalf(
        Config,
        device,
        encoder,
        pipelines,
        args,
    );
}

// ============================================================================
// Full-model forward decode (Step 2d)
// ============================================================================

/// Parameterized full-model decode args — the weight buffer
/// type depends on the quantization format.  The alias
/// `ForwardDecodeArgs` preserves backward compatibility
/// with existing Q1 code.
pub fn ForwardDecodeArgsT(
    comptime WeightBuf: type,
) type {
    return struct {
        // Model-level quantized weights.
        embedding: WeightBuf,
        lm_head: WeightBuf,
        final_norm_scale: objc.Object,

        // Per-layer quantized weight buffers.
        q_proj: []const WeightBuf,
        k_proj: []const WeightBuf,
        v_proj: []const WeightBuf,
        o_proj: []const WeightBuf,
        gate_proj: []const WeightBuf,
        up_proj: []const WeightBuf,
        down_proj: []const WeightBuf,

        // Per-layer norm scale buffers (f32).
        attn_norm: []const metal.Buffer,
        ffn_norm: []const metal.Buffer,
        q_norm: []const metal.Buffer,
        k_norm: []const metal.Buffer,

        // Per-layer KV caches (f16).
        k_cache: []const metal.HalfBuffer,
        v_cache: []const metal.HalfBuffer,

        // Activation scratch (shared across all layers).
        residual: objc.Object,
        norm_out: objc.Object,
        q: objc.Object,
        k: objc.Object,
        v: objc.Object,
        attn_out: objc.Object,
        proj_out: objc.Object,
        attn_scratch: objc.Object,
        gate: objc.Object,
        up: objc.Object,
        mlp_out: objc.Object,

        // Forward pass I/O.
        token_ids: objc.Object,
        logits: objc.Object,

        // GPU completion flag for spin-wait.
        flag_buf: objc.Object,
        flag_ptr: *volatile u32,

        // Sequence state.
        token_id: u32,
        position: u32,
    };
}

pub const ForwardDecodeArgs =
    ForwardDecodeArgsT(metal.PackedBuffer);

/// Encode a full single-token decode pass into one compute
/// command encoder:
///   embedding lookup → N × forwardBlock → final RMSNorm →
///   LM head QMV → [vocab_size] f32 logits.
///
/// Writes the token ID into the `token_ids` buffer (CPU →
/// shared memory) before any GPU work is dispatched.  The
/// caller must not read `logits` until the command buffer
/// has completed (Rule 26).
///
/// Dispatch count: 1 + N×18 + 2 (embedding + N blocks ×
/// 18 kernels + final norm + LM head).
/// For Bonsai1_7B: 1 + 28×18 + 2 = 507.
pub fn forwardDecode(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,

fn encodeAttentionHalf(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    encodeAttentionProjections(
        Config,
        device,
        encoder,
        pipelines,
        a,
    );
    encodeAttentionGather(
        Config,
        device,
        encoder,
        pipelines,
        a,
    );
}

/// Encode RMSNorm → Q/K/V projections → QK norms.
/// RoPE and KV cache update follow in a separate helper
/// to stay within the 70-line function limit.
fn encodeAttentionProjections(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    const kv_qmv = QMVDims{
        .M = Config.kv_dim,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    const q_qmv = QMVDims{
        .M = Config.query_dim,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    // Fused norm needs K <= 4096 for threadgroup memory
    // and both single + pair pipelines available.
    const can_fuse_norm = comptime (Config.hidden_size % Config.group_size == 0) and
        (Config.hidden_size <= 4096) and
        (Config.hidden_size >= 256) and
        (Config.hidden_size / 32 <= Config.group_size);
    const use_fused_norm =
        if (comptime Config.quant_format == .q4_mlx)
            can_fuse_norm and
                device.spec_q4mv_fused_norm_f16io != null and
                device.spec_q4mv_fused_norm_f16io.?
                    .max_threads_per_group >= 512 and
                device.spec_q4mv_fused_norm_pair_f16io != null and
                device.spec_q4mv_fused_norm_pair_f16io.?
                    .max_threads_per_group >= 512 and
                q_qmv.K == device.spec_q4_hidden_K
        else
            can_fuse_norm and
                device.spec_qmv_fused_norm_f16io != null and
                device.spec_qmv_fused_norm_f16io.?
                    .max_threads_per_group >= 512 and
                device.spec_qmv_fused_norm_pair_f16io != null and
                device.spec_qmv_fused_norm_pair_f16io.?
                    .max_threads_per_group >= 512 and
                q_qmv.K == device.spec_hidden_K;
    if (use_fused_norm) {
        encodeAttnProjFusedNorm(
            Config,
            device,
            encoder,
            a,
            q_qmv,
            kv_qmv,
        );
    } else {
        encodeAttnProjSeparateNorm(
            Config,
            device,
            encoder,
            pipelines,
            a,
            q_qmv,
            kv_qmv,
        );
    }
    // Q/K norm + RoPE + KV cache update are now fused into
    // the GQA attention kernel (encodeAttentionGather).
    // Single barrier: wait for Q/K/V projection writes
    // before the fused GQA kernel reads them.
    bufferBarrier(encoder);
}

/// Fused-norm path: each QMV kernel reads the f32 residual
/// and f16 norm_scale directly, computes RMSNorm in TG memory.
/// Saves 1 RMSNorm dispatch + 1 barrier vs the separate path.
fn encodeAttnProjFusedNorm(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    a: ForwardBlockArgsT(Config.WeightBuffer),
    q_qmv: QMVDims,
    kv_qmv: QMVDims,
) void {
    std.debug.assert(q_qmv.K == Config.hidden_size);
    std.debug.assert(kv_qmv.K == Config.hidden_size);
    if (comptime Config.quant_format == .q4_mlx) {
        // Q projection: fused norm + single Q4 QMV.
        dispatchQ4FusedNormQMVf16io(
            device,
            encoder,
            a.q_proj,
            a.residual,
            a.q,
            a.attn_norm_scale,
            q_qmv,
        );
        // KV projection: fused norm + paired Q4 QMV.
        dispatchQ4FusedNormPairQMVf16io(
            device,
            encoder,
            a.k_proj,
            a.v_proj,
            a.residual,

fn encodeRoPEAndKVCache(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgs,
) void {
    std.debug.assert(
        a.position < Config.max_context_length,
    );
    std.debug.assert(Config.head_dim % 2 == 0);
    // Q RoPE: applied in-place (Q is read by GQA attention).
    dispatchRoPE(device, encoder, pipelines.rope_f16, a.q, .{
        .num_heads = Config.num_query_heads,
        .head_dim = Config.head_dim,
        .position = a.position,
        .rope_theta = Config.rope_theta,
    });
    // Fused RoPE K + KV cache update: applies RoPE to K and
    // writes both K and V directly to their caches.  Saves
    // 1 dispatch + 1 barrier vs separate rope_k + cache_update.
    dispatchFusedRoPEKVCache(
        device,
        encoder,
        pipelines.fused_rope_k_kv_cache_f16,
        a.k,
        a.v,
        a.k_cache,
        a.v_cache,
        .{
            .num_kv_heads = Config.num_kv_heads,
            .head_dim = Config.head_dim,
            .position = a.position,
            .max_context_length = Config.max_context_length,
            .rope_theta = Config.rope_theta,
        },
    );
    // Single barrier: wait for both Q RoPE and fused K/V
    // cache write before GQA attention reads Q and k/v caches.
    bufferBarrier(encoder);
}

/// Encode GQA attention → O projection → residual add.
/// Reads from Q buffer and KV cache written by
/// `encodeAttentionProjections`.
fn encodeAttentionGather(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    // Use the fused kernel that applies Q/K norm + RoPE +
    // KV cache update inside GQA when seq_len fits in TG
    // memory.  Falls back to separate dispatches otherwise.
    const TG_SEQ_LIMIT: u32 = 1024;
    if (a.seq_len <= TG_SEQ_LIMIT) {
        dispatchGQAAttentionFusedTG(
            device,
            encoder,
            pipelines.gqa_attention_fused_f16io_tg,
            a.q,
            a.k_cache,
            a.v_cache,
            a.attn_out,
            a.k,
            a.v,
            a.q_norm_scale,
            a.k_norm_scale,
            .{
                .num_query_heads = Config.num_query_heads,
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .seq_len = a.seq_len,
                .max_context_length = Config.max_context_length,
                .heads_per_kv_group = Config.heads_per_kv_group,
                .position = a.position,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
    } else {
        // Long-sequence fallback: separate norm+RoPE+cache,
        // then the scratch-based GQA kernel.
        dispatchFusedNormRoPE(
            device,
            encoder,
            pipelines.fused_norm_rope_f16,
            a.q,
            a.q_norm_scale,
            .{
                .num_heads = Config.num_query_heads,
                .head_dim = Config.head_dim,
                .position = a.position,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
        dispatchFusedKNormRoPEKVCache(
            device,
            encoder,
            pipelines.fused_k_norm_rope_kv_cache_f16,
            a.k,
            a.v,
            a.k_cache,
            a.v_cache,
            a.k_norm_scale,
            .{
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .position = a.position,
                .max_context_length = Config.max_context_length,
                .eps = 1e-6,
                .rope_theta = Config.rope_theta,
            },
        );
        bufferBarrier(encoder);
        dispatchGQAAttention(
            device,
            encoder,
            pipelines.gqa_attention_f16io,
            a.q,
            a.k_cache,
            a.v_cache,
            a.attn_out,
            a.attn_scratch,
            .{
                .num_query_heads = Config.num_query_heads,
                .num_kv_heads = Config.num_kv_heads,
                .head_dim = Config.head_dim,
                .seq_len = a.seq_len,
                .max_context_length = Config.max_context_length,
                .heads_per_kv_group = Config.heads_per_kv_group,
            },
        );
    }
    bufferBarrier(encoder);
    // Fused QMV + residual accumulate: the O-projection result
    // is added directly to the f32 residual (residual[row] += acc)
    // instead of writing f16 to proj_out then dispatching
    // residual_add_f16.  Saves one dispatch + one barrier.
    const o_dims = QMVDims{
        .M = Config.hidden_size,
        .K = Config.query_dim,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16ioResadd(
            device,
            encoder,
            a.o_proj,
            a.attn_out,
            a.residual,
            o_dims,
        );
    } else {
        dispatchQMVf16ioResadd(
            device,
            encoder,
            a.o_proj,
            a.attn_out,
            a.residual,
            o_dims,
        );
    }
    bufferBarrier(encoder);
}

/// Encode the MLP half of a decoder block:
/// RMSNorm → gate/up proj → SiLU⊙mul → down proj →
/// residual add.
fn encodeMLPHalf(
    comptime Config: type,
    device: *const metal.Device,
    encoder: objc.Object,
    pipelines: *const TransformerPipelines,
    a: ForwardBlockArgsT(Config.WeightBuffer),
) void {
    const mlp_qmv = QMVDims{
        .M = Config.intermediate_size,
        .K = Config.hidden_size,
        .group_size = Config.group_size,
    };
    // Gate and up projections share the same input and dims.
    // Best path: fuse FFN-RMSNorm + gate+up+SiLU into a
    // single kernel — saves 2 dispatches + 2 barriers per
    // block by reading the f32 residual directly.
    const can_fuse = comptime (Config.hidden_size % Config.group_size == 0) and
        (Config.hidden_size <= 6144) and
        (Config.hidden_size >= 256) and
        (Config.hidden_size / 32 <= Config.group_size);
    // Fused norm needs K <= 4096 for threadgroup memory.
    const can_fuse_norm = can_fuse and
        comptime (Config.hidden_size <= 4096);
    const use_fused_norm_silu =
        if (comptime Config.quant_format == .q4_mlx)
            can_fuse_norm and
                device.spec_q4mv_fused_norm_pair_silu_f16io !=
                    null and
                device.spec_q4mv_fused_norm_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_q4_hidden_K
        else
            can_fuse_norm and
                device.spec_qmv_fused_norm_pair_silu_f16io !=
                    null and
                device.spec_qmv_fused_norm_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_hidden_K;
    const use_fused_silu =
        if (comptime Config.quant_format == .q4_mlx)
            !use_fused_norm_silu and can_fuse and
                device.spec_q4mv_fused_pair_silu_f16io !=
                    null and
                device.spec_q4mv_fused_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_q4_hidden_K
        else
            !use_fused_norm_silu and can_fuse and
                device.spec_qmv_fused_pair_silu_f16io !=
                    null and
                device.spec_qmv_fused_pair_silu_f16io.?
                    .max_threads_per_group >= 512 and
                mlp_qmv.K == device.spec_hidden_K;
    if (use_fused_norm_silu) {
        // Fused norm+gate+up+SiLU: reads f32 residual
        // directly, computes RMSNorm in TG memory, then
        // gate+up QMV with SiLU.  Skips norm_out, gate,
        // and up buffers entirely.
        if (comptime Config.quant_format == .q4_mlx) {
            dispatchQ4FusedNormPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.residual,
                a.mlp_out,
                a.ffn_norm_scale,
                mlp_qmv,
            );
        } else {
            dispatchFusedNormPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.residual,
                a.mlp_out,
                a.ffn_norm_scale,
                mlp_qmv,
            );
        }
    } else if (use_fused_silu) {

    } else if (use_fused_silu) {
        // Fused gate+up+SiLU: needs separate RMSNorm first.
        dispatchRMSNorm(
            device,
            encoder,
            if (comptime Config.quant_format == .q4_mlx)
                pipelines.rms_norm_bf16_f16out
            else
                pipelines.rms_norm_f16out,
            a.residual,
            a.ffn_norm_scale,
            a.norm_out,
            .{
                .hidden_size = Config.hidden_size,
                .num_tokens = 1,
                .eps = 1e-6,
            },
        );
        bufferBarrier(encoder);
        if (comptime Config.quant_format == .q4_mlx) {
            dispatchQ4MVFusedPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.norm_out,
                a.mlp_out,
                mlp_qmv,
            );
        } else {
            dispatchQMVFusedPairSiLUf16io(
                device,
                encoder,
                a.gate_proj,
                a.up_proj,
                a.norm_out,
                a.mlp_out,
                mlp_qmv,
            );
        }
    } else {
        // Non-fused-norm paths need separate RMSNorm.
        dispatchRMSNorm(
            device,
            encoder,
            if (comptime Config.quant_format == .q4_mlx)
                pipelines.rms_norm_bf16_f16out
            else
                pipelines.rms_norm_f16out,
            a.residual,
            a.ffn_norm_scale,
            a.norm_out,
            .{
                .hidden_size = Config.hidden_size,
                .num_tokens = 1,
                .eps = 1e-6,
            },
        );
        bufferBarrier(encoder);
        if (comptime Config.quant_format == .q4_mlx) {
            if (can_fuse) {
                dispatchQ4MVFusedPairf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.up_proj,
                    a.norm_out,
                    a.gate,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            } else {
                dispatchQ4MVf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.norm_out,
                    a.gate,
                    mlp_qmv,
                );
                dispatchQ4MVf16io(
                    device,
                    encoder,
                    a.up_proj,
                    a.norm_out,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            }
        } else {
            if (can_fuse) {
                dispatchQMVFusedPairf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.up_proj,
                    a.norm_out,
                    a.gate,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            } else {
                dispatchQMVf16io(
                    device,
                    encoder,
                    a.gate_proj,
                    a.norm_out,
                    a.gate,
                    mlp_qmv,
                );
                dispatchQMVf16io(
                    device,
                    encoder,
                    a.up_proj,
                    a.norm_out,
                    a.up,
                    mlp_qmv,
                );
                bufferBarrier(encoder);
                dispatchSiLUElementwiseMul(
                    device,
                    encoder,
                    pipelines.silu_elementwise_mul_f16,
                    a.gate,
                    a.up,
                    a.mlp_out,
                    Config.intermediate_size,
                );
            }
        }
    }
    bufferBarrier(encoder);
    // Fused QMV + residual accumulate: the down-projection
    // result is added directly to the f32 residual instead of
    // writing f16 to proj_out then dispatching residual_add_f16.
    // Saves one dispatch + one barrier.
    const down_dims = QMVDims{
        .M = Config.hidden_size,
        .K = Config.intermediate_size,
        .group_size = Config.group_size,
    };
    if (comptime Config.quant_format == .q4_mlx) {
        dispatchQ4MVf16ioResadd(
            device,
            encoder,
            a.down_proj,
            a.mlp_out,
            a.residual,
            down_dims,
        );
    } else {
        dispatchQMVf16ioResadd(
            device,
            encoder,
            a.down_proj,
            a.mlp_out,
            a.residual,
            down_dims,
        );
    }
    bufferBarrier(encoder);
}

// ============================================================================
