    constexpr uint nibble_bytes_per_row = K / 2;

    const bool row0_valid = row0 < M;
    const bool row1_valid = row1 < M;
    const uint safe_row0 = min(row0, M - 1);
    const uint safe_row1 = min(row1, M - 1);

