/// Dispatch the GPU completion flag kernel: atomic-write 1
/// to flag[0].  Must be the last dispatch before endEncoding
/// so the CPU can spin-wait on the flag instead of calling
/// waitUntilCompleted (~100-150 us Mach trap saved).
///
/// A bufferBarrier must precede this dispatch to ensure all
/// preceding kernel writes are visible before the flag is
/// set.
///
/// Dispatch: 1 threadgroup, 1 thread.
fn dispatchCompletionFlag(
    device: *const metal.Device,
    encoder: objc.Object,
    pipeline: metal.ComputePipeline,
    flag_buf: objc.Object,
) void {
    std.debug.assert(encoder.value != null);
    std.debug.assert(flag_buf.value != null);

    setRawBuffer(encoder, flag_buf, 0, 0);

    const one = metal.MTLSize{
        .width = 1,
        .height = 1,
        .depth = 1,
    };
    device.dispatchCustom(
        encoder,
        pipeline,
        one,
        one,
    );
}

pub fn dispatchCustom(
    self: *const Device,
    encoder: objc.Object,
    pipeline: ComputePipeline,
    grid: MTLSize,
    group: MTLSize,
) void {
    std.debug.assert(grid.width > 0);
    std.debug.assert(group.width > 0);
    std.debug.assert(self.command_queue.value != null);

    // Threadgroup size must not exceed pipeline's hardware
    // limit.  Width × height × depth is the total thread
    // count per threadgroup.
    const threads_per_group =
        group.width * group.height * group.depth;
    std.debug.assert(
        threads_per_group <= pipeline.max_threads_per_group,
    );

    encoder.msgSend(
        void,
        "setComputePipelineState:",
        .{pipeline.state.value},
    );

    encoder.msgSend(
        void,
        "dispatchThreadgroups:threadsPerThreadgroup:",
        .{ grid, group },
    );
}

/// Commit a command buffer and wait for completion
/// (synchronous).
pub fn commitAndWait(
    self: *const Device,
    cmd_buf: objc.Object,
) void {
    // Assert the device is in a valid state.
    std.debug.assert(self.command_queue.value != null);
    std.debug.assert(cmd_buf.value != null);

    cmd_buf.msgSend(void, "commit", .{});
    cmd_buf.msgSend(void, "waitUntilCompleted", .{});
}

